+            let outcome = execute_device_auth_step("AB-CD", "default", &tmp, None, true);
+            match outcome {
+                DeviceAuthStepOutcome::Failed { error_kind, .. } => {
+                    assert_eq!(error_kind.as_deref(), Some("invalid_code"));
+                }
